code = """import json, re, pandas as pd

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r') as f:
            return json.load(f)
    return v

alive_recs = load_records(var_call_p20aQLAid3muUUhRSFLheuqB)
cdh1_recs = load_records(var_call_dTl18m7KbORJK3Wo6z9tF4hD)

alive_df = pd.DataFrame(alive_recs)
cdh1_df = pd.DataFrame(cdh1_recs)

# extract TCGA barcode from Patient_description
alive_df['ParticipantBarcode'] = alive_df['Patient_description'].str.extract(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', expand=False)

alive_df = alive_df.dropna(subset=['ParticipantBarcode'])

cdh1_set = set(cdh1_df['ParticipantBarcode'].dropna().unique())
alive_df['cdh1_mut'] = alive_df['ParticipantBarcode'].isin(cdh1_set)

# group by histological_type
grp = alive_df.groupby('histological_type', dropna=False).agg(total_alive=('ParticipantBarcode','nunique'), cdh1_mutated=('cdh1_mut','sum'))
grp['pct_cdh1_mut'] = (grp['cdh1_mutated'] / grp['total_alive']) * 100

grp = grp.sort_values(['pct_cdh1_mut','cdh1_mutated','total_alive'], ascending=False)

top3 = grp.head(3).reset_index()
# round percent
top3['pct_cdh1_mut'] = top3['pct_cdh1_mut'].round(2)
result = top3.to_dict(orient='records')

print('__RESULT__:')
print(json.dumps(result))"""

